import React from "react";
import WeatherOverlay from "./WeatherOverlay";
import Radar from "./Radar";
import Forecast from "./Forecast";
import BottomBar from "./BottomBar"; // <-- use your existing BottomBar

// tiny safe getter
const get = (obj, path, fallback = "") =>
  path.split(".").reduce((o, k) => (o && o[k] != null ? o[k] : null), obj) ?? fallback;

export default function WeatherApp({ weather }) {
  // --- fallback demo data if prop not provided ---
  const demo = {
    current: {
      temp: 72,
      description: "Few clouds",
      icon: "02d",
      city: "Atlanta, US",
      feels_like: 73,
      wind_speed: 5,
      humidity: 62,
    },
    hourly: Array.from({ length: 12 }).map((_, i) => ({
      dt: Math.floor(Date.now() / 1000) + i * 3600,
      temp: 70 + i,
      pop: i % 3 === 0 ? 0.4 : 0.1,
      weather: [{ description: i % 2 ? "Clouds" : "Clear", icon: i % 2 ? "03d" : "01d" }],
    })),
    daily: [
      { dt: Date.now() / 1000 + 86400 * 1, temp: { max: 86, min: 70 }, description: "Partly cloudy", icon: "02d" },
      { dt: Date.now() / 1000 + 86400 * 2, temp: { max: 88, min: 72 }, description: "Showers", icon: "10d" },
      { dt: Date.now() / 1000 + 86400 * 3, temp: { max: 90, min: 73 }, description: "Sunny", icon: "01d" },
      { dt: Date.now() / 1000 + 86400 * 4, temp: { max: 84, min: 69 }, description: "Thunderstorms", icon: "11d" },
      { dt: Date.now() / 1000 + 86400 * 5, temp: { max: 83, min: 68 }, description: "Overcast", icon: "04d" },
      { dt: Date.now() / 1000 + 86400 * 6, temp: { max: 81, min: 67 }, description: "Light rain", icon: "10d" },
      { dt: Date.now() / 1000 + 86400 * 7, temp: { max: 85, min: 69 }, description: "Clear", icon: "01d" },
    ],
  };

  const data = weather ?? demo;

  // --- pull fields ---
  const current = data.current ?? {};
  const city = get(current, "city", "—");
  const desc = get(current, "description", "—");
  const temp = Math.round(get(current, "temp", 0));
  const feels = Math.round(get(current, "feels_like", temp));
  const wind = get(current, "wind_speed", 0);
  const humidity = get(current, "humidity", 0);
  const icon = get(current, "icon", "01d");
  const iconUrl = `https://openweathermap.org/img/wn/${icon}@2x.png`;

  const hourly = (data.hourly ?? []).slice(0, 12);
  const daily = data.daily ?? [];

  return (
    <div className="relative min-h-screen w-full overflow-x-hidden bg-white dark:bg-black">
      {/* Dynamic background overlay (behind everything) */}
      <div className="absolute inset-0 -z-10">
        <WeatherOverlay condition={desc} timeOfDay="false" />
      </div>

      {/* Page content */}
      <main className="relative z-10 mx-auto w-full max-w-5xl px-4 py-6 flex flex-col gap-6">
        {/* NOW CARD */}
        <section className="w-full rounded-2xl overflow-hidden shadow-xl border border-white/10 bg-black/50 backdrop-blur-md">
          <div className="p-4 text-center text-white/90 font-semibold text-lg bg-black/40 border-b border-white/10">
            Currently: {desc}
          </div>

          <div className="p-6 flex items-center justify-between">
            <div className="flex flex-col">
              <div className="text-white/90 text-2xl font-semibold">{city}</div>
              <div className="text-white text-6xl font-bold mt-1">{temp}°</div>
              <div className="mt-2 text-white/70 text-sm">
                Feels like {feels}° • Wind {wind} mph • Humidity {humidity}%
              </div>
            </div>
            <img
              src={iconUrl}
              alt={desc}
              className="w-20 h-20 drop-shadow-[0_6px_22px_rgba(128,90,213,0.55)]"
            />
          </div>

          {/* 12-hour strip */}
          <div className="pt-2 pb-4">
            <div className="px-4 pb-2 text-white/80 text-sm font-semibold">
              Next 12 Hours
            </div>
            <div className="relative">
              <div className="pointer-events-none absolute left-0 top-0 h-full w-8 bg-gradient-to-r from-black/40 to-transparent z-10" />
              <div className="pointer-events-none absolute right-0 top-0 h-full w-8 bg-gradient-to-l from-black/40 to-transparent z-10" />

              <div className="px-4 flex gap-3 overflow-x-auto snap-x snap-mandatory scrollbar-thin scrollbar-thumb-white/10 scrollbar-track-transparent">
                {hourly.length ? (
                  hourly.map((h, i) => {
                    const label =
                      i === 0
                        ? "Now"
                        : new Date((h.dt ?? 0) * 1000).toLocaleTimeString([], {
                            hour: "numeric",
                          });
                    const hIcon = h?.weather?.[0]?.icon ?? "01d";
                    const hDesc = h?.weather?.[0]?.description ?? "";
                    const iconUrlSmall = `https://openweathermap.org/img/wn/${hIcon}.png`;
                    const pop =
                      typeof h.pop === "number"
                        ? Math.round(h.pop * 100)
                        : null;

                    return (
                      <div
                        key={h.dt ?? i}
                        className="snap-start shrink-0 w-20 bg-black/35 backdrop-blur-md border border-white/10 rounded-xl shadow-md py-3 px-2 text-center"
                      >
                        <div className="text-[11px] text-white/70 font-medium">{label}</div>
                        <img
                          src={iconUrlSmall}
                          alt={hDesc}
                          className="w-10 h-10 mx-auto my-1 drop-shadow-[0_6px_22px_rgba(128,90,213,0.35)]"
                        />
                        <div className="text-white text-base font-semibold">
                          {Math.round(h.temp ?? 0)}°
                        </div>
                        {typeof pop === "number" && (
                          <div className="text-[11px] text-white/60 mt-1">{pop}% rain</div>
                        )}
                      </div>
                    );
                  })
                ) : (
                  <div className="px-4 py-3 text-white/60 text-sm">
                    Hourly forecast unavailable.
                  </div>
                )}
              </div>
            </div>
          </div>
        </section>

        {/* RADAR */}
        <section className="w-full rounded-2xl overflow-hidden shadow-lg border border-white/10 bg-black/50 backdrop-blur-md">
          <div className="p-3 text-white/80 text-sm font-semibold bg-black/40 border-b border-white/10">
            Radar
          </div>
          {/* Keep Radar in its own container so Leaflet z-index plays nice */}
          <div className="h-[60vh] sm:h-[65vh]">
            <Radar city={city} pins={[]} />
          </div>
        </section>

        {/* FORECAST (daily) */}
        <section className="w-full">
          <div className="mb-2 px-1 text-white/80 text-sm font-semibold">
           
          </div>
          <Forecast daily={daily} />
        </section>
      </main>

      {/* Bottom bar */}
      <div className="pointer-events-none fixed inset-x-0 bottom-0 z-20 flex justify-center pb-4">
        <div className="pointer-events-auto">
          <BottomBar />
        </div>
      </div>
    </div>
  );
}
